+#[test]
+fn expected_loss_recover_on_fully_recoverable() {
+    let lm = LossMatrix::default();
+    let p = Posterior {
+        recoverable: 1_000_000,
+        ambiguous: 0,
+        unrecoverable: 0,
+    };
