+
+#[test]
+fn const_assignment_after_init_fails() {
+    let mut chain = fresh_chain();
+    chain.declare_const("PI".into(), 20).unwrap();
+    chain
+        .initialize_binding("PI", EnvValue::Number(3_141_593), Label::Public)
