+        decision_id: "dec-001".to_string(),
+        timestamp_ns: 1_000_000,
+        epoch: SecurityEpoch::GENESIS,
+        evidence_refs: vec!["ev-001".to_string()],
+        ..ContainmentContext::default()
+    }
